A SourceMod plugin code was provided by user 'gibs' which hooks into the `round_end` event. It selects a random player from each team (Terrorists and CTs) using `GetRandomPlayer` function and switches their teams with `CS_SwitchTeam`. The plugin is implemented as follows:
```sourcepawn
#pragma semicolon 1
#include <sourcemod>
#include <cstrike>
#pragma newdecls required

public void OnPluginStart() {
    HookEvent("round_end", Event_RoundEnd, EventHookMode_PostNoCopy);
}

public void Event_RoundEnd(Event event, const char[] name, bool dontBroadcast) {
    int rand_t = GetRandomPlayer(CS_TEAM_T);
    int rand_ct = GetRandomPlayer(CS_TEAM_CT);
    if(rand_t != 0 && rand_ct != 0) {
        CS_SwitchTeam(rand_t, CS_TEAM_CT);
        CS_SwitchTeam(rand_ct, CS_TEAM_T);
    }
}

int GetRandomPlayer(int team) {
    int[] clients = new int[MaxClients];
    int total = 0;
    for (int client = 1; client <= MaxClients; ++client) {
        if(!IsClientInGame(client) || GetClientTeam(client) != team) continue;
        clients[total++] = client;
    }
    if(total == 0) return 0;
    return clients[GetRandomInt(0, total - 1)];
}
```
The plugin should be saved as a `.sp` file and compiled following the SourcePawn compilation guide. Additional refinements were discussed regarding array bounds and static variables for optimization.

